func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const maxCost = 1e18

	for j := 0; j < len(oris); j++ {
		ori := oris[j]
		des := dess[j]

		bestIdx := -1
		bestIncrease := maxCost
		found := false

		limit := dispatch.AssignsLen
		if limit < MAXASSIGNS {
			limit++
		}

		for ii := 0; ii < limit; ii++ {
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+j, ori, des) {
				dispatch.Assigns[ii].Cost = -1
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost < 0 {
				dispatch.Assigns[ii].RemoveShip(total_ship + j)
				dispatch.Assigns[ii].GenRoute()
				continue
			}
			increase := newCost - oldCost
			if ii == dispatch.AssignsLen {
				increase = newCost
			}
			if increase < bestIncrease {
				bestIncrease = increase
				bestIdx = ii
				found = true
			}
			dispatch.Assigns[ii].RemoveShip(total_ship + j)
			dispatch.Assigns[ii].GenRoute()
		}

		if found {
			dispatch.Assigns[bestIdx].AddShip(total_ship+j, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+j, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
			} else {
				for i := 0; i < dispatch.AssignsLen; i++ {
					if dispatch.Assigns[i].AddShip(total_ship+j, ori, des) {
						dispatch.Assigns[i].GenRoute()
						break
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
